
.phone-container {
  width: 100%;
  max-width: 375px;
  margin: 0 auto;
  padding: 20px;
}

.phone-frame {
  width: 100%;
  aspect-ratio: 9/19;
  background: var(--phone-screen);
  border-radius: 40px;
  border: 12px solid var(--phone-frame);
  box-shadow: 
    0 0 0 2px #3d3d3d,
    0 20px 60px rgba(0, 0, 0, 0.3);
  position: relative;
  overflow: hidden;
  display: flex;
  flex-direction: column;
}

// 刘海
.notch {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 150px;
  height: 30px;
  background: var(--phone-frame);
  border-radius: 0 0 20px 20px;
  z-index: 100;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
}

.notch-speaker {
  width: 60px;
  height: 4px;
  background: #1a1a1a;
  border-radius: 2px;
}

.notch-camera {
  width: 8px;
  height: 8px;
  background: #1a1a1a;
  border-radius: 50%;
}

// 状态栏
.status-bar {
  height: 44px;
  background: var(--status-bar-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 20px;
  padding-top: 10px;
  font-size: 14px;
  color: var(--text-primary);
}

.status-left {
  font-weight: 600;
}

.status-right {
  display: flex;
  gap: 6px;
  align-items: center;
  
  i {
    font-size: 12px;
  }
}

// 聊天头部
.chat-header {
  height: 44px;
  background: var(--status-bar-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 15px;
  border-bottom: 1px solid var(--border-color);
}

.back-btn, .more-btn {
  font-size: 18px;
  color: var(--text-primary);
  cursor: pointer;
}

.chat-title {
  text-align: center;
}

.contact-name {
  font-size: 16px;
  font-weight: 600;
  color: var(--text-primary);
}

.contact-status {
  font-size: 11px;
  color: var(--text-light);
}

// 角色状态卡片
.status-card {
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  margin: 10px 15px;
  border-radius: 16px;
  padding: 15px;
  display: flex;
  align-items: center;
  gap: 15px;
  color: white;
}

.status-avatar {
  position: relative;
  
  img {
    width: 60px;
    height: 60px;
    border-radius: 50%;
    border: 3px solid rgba(255, 255, 255, 0.3);
  }
}

.online-dot {
  position: absolute;
  bottom: 3px;
  right: 3px;
  width: 14px;
  height: 14px;
  background: var(--accent-color);
  border-radius: 50%;
  border: 2px solid white;
}

.status-info {
  flex: 1;
}

.status-mood, .status-location {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 14px;
  margin-bottom: 6px;
  
  i {
    font-size: 16px;
  }
}

// 属性面板
.stats-panel {
  background: var(--status-bar-bg);
  margin: 0 15px 10px;
  border-radius: 12px;
  padding: 12px 15px;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.05);
}

.stat-item {
  display: flex;
  align-items: center;
  gap: 10px;
  margin-bottom: 10px;
  
  &:last-child {
    margin-bottom: 0;
  }
}

.stat-label {
  width: 50px;
  font-size: 12px;
  color: var(--text-secondary);
}

.stat-bar {
  flex: 1;
  height: 8px;
  background: #e8e8e8;
  border-radius: 4px;
  overflow: hidden;
}

.stat-progress {
  height: 100%;
  background: linear-gradient(90deg, #ff6b6b, #ee5a5a);
  border-radius: 4px;
  transition: width 0.3s ease;
  
  &.hp {
    background: linear-gradient(90deg, #07c160, #05a350);
  }
  
  &.mp {
    background: linear-gradient(90deg, #5b8ff9, #4a7de4);
  }
}

.stat-value {
  width: 30px;
  font-size: 12px;
  color: var(--text-secondary);
  text-align: right;
}

// 聊天内容
.chat-content {
  flex: 1;
  background: var(--chat-bg);
  overflow-y: auto;
  padding: 15px;
}

.chat-time {
  text-align: center;
  font-size: 12px;
  color: var(--text-light);
  margin-bottom: 15px;
}

.message {
  display: flex;
  margin-bottom: 15px;
  
  &.received {
    .message-bubble {
      background: var(--chat-bubble-other);
      border-radius: 4px 16px 16px 16px;
    }
  }
  
  &.sent {
    justify-content: flex-end;
    
    .message-bubble {
      background: var(--chat-bubble-me);
      border-radius: 16px 4px 16px 16px;
    }
  }
}

.message-avatar {
  margin-right: 10px;
  
  img {
    width: 36px;
    height: 36px;
    border-radius: 50%;
  }
}

.message-bubble {
  max-width: 70%;
  padding: 10px 14px;
  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.1);
}

.message-text {
  font-size: 14px;
  color: var(--text-primary);
  line-height: 1.5;
}

// 输入栏
.input-bar {
  height: 50px;
  background: #f7f7f7;
  display: flex;
  align-items: center;
  padding: 0 15px;
  gap: 10px;
  border-top: 1px solid var(--border-color);
}

.voice-btn, .more-btn {
  font-size: 24px;
  color: var(--text-secondary);
  cursor: pointer;
}

.input-box {
  flex: 1;
  
  input {
    width: 100%;
    height: 36px;
    border: none;
    border-radius: 4px;
    padding: 0 12px;
    font-size: 14px;
    background: white;
    
    &::placeholder {
      color: var(--text-light);
    }
  }
}

// Home Indicator
.home-indicator {
  height: 34px;
  background: var(--status-bar-bg);
  display: flex;
  align-items: center;
  justify-content: center;
  
  &::after {
    content: '';
    width: 134px;
    height: 5px;
    background: #c4c4c4;
    border-radius: 3px;
  }
}
